if (! function_exists('image_generator_procedural')) {
    function image_generator_procedural($mode = null, $width = null, $height = null, $colors = null, $iterations = null, $params = null, $filename = null)
    {
        // Procedural image generator - creates PNG images from scratch using GD
        // Supports fractals, gradients, patterns, and abstract art

        if (!extension_loaded('gd')) {
            return ['error' => 'GD extension not loaded, cannot generate images'];
        }

        $mode = isset($mode) ? (string)$mode : 'mandelbrot';
        $width = isset($width) ? min(max((int)$width, 32), 2048) : 512;
        $height = isset($height) ? min(max((int)$height, 32), 2048) : 512;
        $iterations = isset($iterations) ? min(max((int)$iterations, 16), 512) : 64;
        $params = isset($params) ? (array)$params : [];

        // Build filename
        $fn = isset($filename) ? (string)$filename : 'procedural_' . $mode . '_' . time();
        if (!str_ends_with($fn, '.png')) {
            $fn .= '.png';
        }
        $output_path = 'storage/agent/workspace/' . $fn;

        // Parse color palette
        $palette = [];
        if (isset($colors) && is_array($colors) && count($colors) > 0) {
            foreach ($colors as $c) {
                $hex = ltrim((string)$c, '#');
                if (strlen($hex) === 6) {
                    $palette[] = [hexdec(substr($hex, 0, 2)), hexdec(substr($hex, 2, 2)), hexdec(substr($hex, 4, 2))];
                }
            }
        }

        // Default palettes if none provided
        if (count($palette) < 2) {
            switch ($mode) {
                case 'mandelbrot':
                case 'julia':
                    $palette = [
                        [0,0,0], [36,0,102], [72,0,153], [108,0,180],
                        [144,0,200], [180,0,220], [216,40,240], [255,80,255],
                        [255,140,255], [255,200,255], [255,230,255], [255,255,255]
                    ];
                    break;
                case 'plasma':
                    $palette = [[0,0,50], [255,0,0], [0,255,0], [255,255,0], [0,0,255], [255,0,255], [0,255,255], [255,255,255]];
                    break;
                case 'spiral':
                    $palette = [[255,0,0], [255,128,0], [255,255,0], [0,255,0], [0,0,255], [128,0,255], [255,0,128]];
                    break;
                default:
                    $palette = [[0,0,0], [64,64,128], [128,128,255], [255,255,255]];
            }
        }

        $palette_count = count($palette);

        // Create image
        $img = @imagecreatetruecolor($width, $height);
        if (!$img) {
            return ['error' => 'Failed to create image'];
        }

        $start_time = microtime(true);

        switch ($mode) {
            case 'mandelbrot':
                // Mandelbrot set: z = z^2 + c
                $minX = -2.5; $maxX = 1.0;
                $minY = -1.2; $maxY = 1.2;
                $zoom = isset($params['zoom']) ? (float)$params['zoom'] : 1.0;
                $centerX = isset($params['cx']) ? (float)$params['cx'] : -0.5;
                $centerY = isset($params['cy']) ? (float)$params['cy'] : 0.0;
                
                $viewWidth = ($maxX - $minX) / $zoom;
                $viewHeight = ($maxY - $minY) / $zoom;
                $minX = $centerX - $viewWidth / 2;
                $maxX = $centerX + $viewWidth / 2;
                $minY = $centerY - $viewHeight / 2;
                $maxY = $centerY + $viewHeight / 2;
                
                for ($py = 0; $py < $height; $py++) {
                    $cy = $minY + ($py / $height) * ($maxY - $minY);
                    for ($px = 0; $px < $width; $px++) {
                        $cx = $minX + ($px / $width) * ($maxX - $minX);
                        $zx = 0.0; $zy = 0.0;
                        $i = 0;
                        while ($i < $iterations) {
                            $zx2 = $zx * $zx;
                            $zy2 = $zy * $zy;
                            if ($zx2 + $zy2 > 4.0) break;
                            $zy = 2.0 * $zx * $zy + $cy;
                            $zx = $zx2 - $zy2 + $cx;
                            $i++;
                        }
                        $color_idx = ($i >= $iterations) ? 0 : (int)(($i / $iterations) * ($palette_count - 1)) + 1;
                        $color_idx = min(max($color_idx, 0), $palette_count - 1);
                        $c = $palette[$color_idx];
                        imagesetpixel($img, $px, $py, imagecolorallocate($img, $c[0], $c[1], $c[2]));
                    }
                }
                $pixel_count = $width * $height;
                break;
                
            case 'julia':
                // Julia set: z = z^2 + c  (c is the Julia parameter)
                $julia_cx = isset($params['cx']) ? (float)$params['cx'] : -0.7;
                $julia_cy = isset($params['cy']) ? (float)$params['cy'] : 0.27;
                
                $minX = -1.5; $maxX = 1.5;
                $minY = -1.5; $maxY = 1.5;
                
                for ($py = 0; $py < $height; $py++) {
                    $zy = $minY + ($py / $height) * ($maxY - $minY);
                    for ($px = 0; $px < $width; $px++) {
                        $zx = $minX + ($px / $width) * ($maxX - $minX);
                        $i = 0;
                        while ($i < $iterations) {
                            $zx2 = $zx * $zx;
                            $zy2 = $zy * $zy;
                            if ($zx2 + $zy2 > 4.0) break;
                            $zy = 2.0 * $zx * $zy + $julia_cy;
                            $zx = $zx2 - $zy2 + $julia_cx;
                            $i++;
                        }
                        $color_idx = ($i >= $iterations) ? 0 : (int)(($i / $iterations) * ($palette_count - 1)) + 1;
                        $color_idx = min(max($color_idx, 0), $palette_count - 1);
                        $c = $palette[$color_idx];
                        imagesetpixel($img, $px, $py, imagecolorallocate($img, $c[0], $c[1], $c[2]));
                    }
                }
                $pixel_count = $width * $height;
                break;
                
            case 'gradient':
                // Linear or radial gradient
                $angle = isset($params['angle']) ? (float)$params['angle'] : 0.0;
                $radian = deg2rad($angle);
                $cos = cos($radian);
                $sin = sin($radian);
                $center_x = $width / 2;
                $center_y = $height / 2;
                $max_dist = sqrt($center_x * $center_x + $center_y * $center_y);
                
                for ($y = 0; $y < $height; $y++) {
                    for ($x = 0; $x < $width; $x++) {
                        $dx = $x - $center_x;
                        $dy = $y - $center_y;
                        $t = ($dx * $cos + $dy * $sin) / $max_dist + 0.5;
                        $t = max(0, min(1, $t));
                        $idx = (int)($t * ($palette_count - 1));
                        if ($idx >= $palette_count) $idx = $palette_count - 1;
                        $c = $palette[$idx];
                        imagesetpixel($img, $x, $y, imagecolorallocate($img, $c[0], $c[1], $c[2]));
                    }
                }
                $pixel_count = $width * $height;
                break;
                
            case 'plasma':
                // Plasma fractal cloud effect
                $size = max($width, $height);
                $power = 1;
                $plasma = array_fill(0, $height, array_fill(0, $width, 0));
                
                // Simple diamond-square plasma
                $step = $size;
                while ($step > 1) {
                    $half = (int)($step / 2);
                    // Square step
                    for ($y = $half; $y < $height + $half; $y += $step) {
                        for ($x = $half; $x < $width + $half; $x += $step) {
                            $avg = 0; $count = 0;
                            $samples = [[-$half,-$half],[$half,-$half],[-$half,$half],[$half,$half]];
                            foreach ($samples as $s) {
                                $sx = $x + $s[0]; $sy = $y + $s[1];
                                if ($sx >= 0 && $sx < $width && $sy >= 0 && $sy < $height) {
                                    $avg += $plasma[$sy][$sx];
                                    $count++;
                                }
                            }
                            if ($count > 0) {
                                $avg = (int)($avg / $count);
                                $px = min(max($x, 0), $width - 1);
                                $py = min(max($y, 0), $height - 1);
                                $plasma[$py][$px] = $avg + rand(-$power, $power);
                            }
                        }
                    }
                    // Diamond step
                    for ($y = 0; $y < $height; $y += $half) {
                        for ($x = ($y + $half) % $step; $x < $width; $x += $step) {
                            $avg = 0; $count = 0;
                            $samples = [[-$half,0],[$half,0],[0,-$half],[0,$half]];
                            foreach ($samples as $s) {
                                $sx = $x + $s[0]; $sy = $y + $s[1];
                                if ($sx >= 0 && $sx < $width && $sy >= 0 && $sy < $height) {
                                    $avg += $plasma[$sy][$sx];
                                    $count++;
                                }
                            }
                            if ($count > 0) {
                                $avg = (int)($avg / $count);
                                $plasma[min(max($y,0),$height-1)][min(max($x,0),$width-1)] = $avg + rand(-$power, $power);
                            }
                        }
                    }
                    $power = max(1, (int)($power * 0.5));
                    $step = $half;
                }
                
                // Normalize and render
                $min_v = PHP_INT_MAX; $max_v = PHP_INT_MIN;
                for ($y = 0; $y < $height; $y++) {
                    for ($x = 0; $x < $width; $x++) {
                        $v = $plasma[$y][$x];
                        if ($v < $min_v) $min_v = $v;
                        if ($v > $max_v) $max_v = $v;
                    }
                }
                $range = $max_v - $min_v;
                if ($range <= 0) $range = 1;
                
                for ($y = 0; $y < $height; $y++) {
                    for ($x = 0; $x < $width; $x++) {
                        $t = ($plasma[$y][$x] - $min_v) / $range;
                        $idx = (int)($t * ($palette_count - 1));
                        if ($idx >= $palette_count) $idx = $palette_count - 1;
                        $c = $palette[$idx];
                        imagesetpixel($img, $x, $y, imagecolorallocate($img, $c[0], $c[1], $c[2]));
                    }
                }
                $pixel_count = $width * $height;
                break;
                
            case 'spiral':
                // Color spiral
                $turns = isset($params['turns']) ? (float)$params['turns'] : 3.0;
                $center_x = $width / 2;
                $center_y = $height / 2;
                $max_radius = min($center_x, $center_y);
                
                for ($y = 0; $y < $height; $y++) {
                    for ($x = 0; $x < $width; $x++) {
                        $dx = $x - $center_x;
                        $dy = $y - $center_y;
                        $radius = sqrt($dx*$dx + $dy*$dy);
                        $angle = atan2($dy, $dx);
                        $t = fmod(($angle / (2 * M_PI) + 0.5) + ($radius / $max_radius) * $turns, 1.0);
                        $idx = (int)($t * ($palette_count - 1));
                        if ($idx >= $palette_count) $idx = $palette_count - 1;
                        $c = $palette[$idx];
                        imagesetpixel($img, $x, $y, imagecolorallocate($img, $c[0], $c[1], $c[2]));
                    }
                }
                $pixel_count = $width * $height;
                break;
                
            case 'noise':
                // Random noise texture
                $seed = isset($params['seed']) ? (int)$params['seed'] : random_int(0, 99999);
                srand($seed);
                for ($y = 0; $y < $height; $y++) {
                    for ($x = 0; $x < $width; $x++) {
                        $t = rand(0, 1000) / 1000.0;
                        $idx = (int)($t * ($palette_count - 1));
                        if ($idx >= $palette_count) $idx = $palette_count - 1;
                        $c = $palette[$idx];
                        imagesetpixel($img, $x, $y, imagecolorallocate($img, $c[0], $c[1], $c[2]));
                    }
                }
                $pixel_count = $width * $height;
                break;
                
            case 'checkerboard':
                // Checkerboard pattern
                $cell_size = isset($params['cell_size']) ? max(2, (int)$params['cell_size']) : 32;
                $color_a = $palette[0] ?? [0,0,0];
                $color_b = $palette[1] ?? [255,255,255];
                $ca = imagecolorallocate($img, $color_a[0], $color_a[1], $color_a[2]);
                $cb = imagecolorallocate($img, $color_b[0], $color_b[1], $color_b[2]);
                
                for ($y = 0; $y < $height; $y++) {
                    for ($x = 0; $x < $width; $x++) {
                        $cell_x = intdiv($x, $cell_size);
                        $cell_y = intdiv($y, $cell_size);
                        $is_even = (($cell_x + $cell_y) % 2) === 0;
                        imagesetpixel($img, $x, $y, $is_even ? $ca : $cb);
                    }
                }
                $pixel_count = $width * $height;
                break;
                
            case 'circles':
                // Overlapping circles
                $count = isset($params['count']) ? min(max((int)$params['count'], 1), 200) : 20;
                $min_r = isset($params['min_radius']) ? max(5, (int)$params['min_radius']) : 10;
                $max_r = isset($params['max_radius']) ? min(max(10, (int)$params['max_radius']), max($width, $height)) : 80;
                
                // Fill background with first palette color
                $bg_c = $palette[0] ?? [0,0,0];
                imagefill($img, 0, 0, imagecolorallocate($img, $bg_c[0], $bg_c[1], $bg_c[2]));
                
                for ($i = 0; $i < $count; $i++) {
                    $cx = rand(0, $width);
                    $cy = rand(0, $height);
                    $r = rand($min_r, $max_r);
                    $ci = $palette[($i % ($palette_count - 1)) + 1] ?? $palette[count($palette)-1];
                    $color = imagecolorallocatealpha($img, $ci[0], $ci[1], $ci[2], 60);
                    imagefilledellipse($img, $cx, $cy, $r * 2, $r * 2, $color);
                }
                $pixel_count = $width * $height;
                break;
                
            default:
                imagedestroy($img);
                return ['error' => "Unknown mode: {$mode}"];
        }

        // Save the image
        $saved = @imagepng($img, $output_path);
        $elapsed = round((microtime(true) - $start_time) * 1000, 1);
        imagedestroy($img);

        if (!$saved) {
            return ['error' => "Failed to save image to {$output_path}"];
        }

        // Get file info
        $file_size = @filesize($output_path);

        return [
            'success' => true,
            'filename' => $fn,
            'path' => $output_path,
            'mode' => $mode,
            'width' => $width,
            'height' => $height,
            'pixels' => $pixel_count,
            'file_size_bytes' => $file_size ?: 0,
            'generation_time_ms' => $elapsed,
            'palette_colors' => $palette_count,
            'iterations' => $iterations,
        ];
    }
